#include <bits/stdc++.h>
using namespace std;
struct ListNode { int val; ListNode* next; ListNode(int x): val(x), next(nullptr){} };
// ListNode* mergeKLists(vector<ListNode*>& lists) { /* your logic */ }
ListNode* makeList(vector<int> v) {
    ListNode dummy(0); ListNode* cur = &dummy;
    for (int x : v) { cur->next = new ListNode(x); cur = cur->next; }
    return dummy.next;
}
void printList(ListNode* h) { while(h){ cout<<h->val<<" "; h=h->next; } cout<<"\n"; }
int main() {
    vector<ListNode*> lists = {makeList({1,4,5}), makeList({1,3,4}), makeList({2,6})};
    printList(mergeKLists(lists));  // Expected: 1 1 2 3 4 4 5 6
    return 0;
}

